  DBSIZE: { minArgs: 0, maxArgs: 0, description: 'Get number of keys in database' },
  PING: { minArgs: 0, maxArgs: 0, description: 'Ping the Redis server' },
  INFO: { minArgs: 0, maxArgs: 1, description: 'Get Redis server info' },
  MGET: { minArgs: 1, maxArgs: 10, description: 'Get multiple values by keys' },
  STRLEN: { minArgs: 1, maxArgs: 1, description: 'Get length of value stored at key' },
