// Search keys using SCAN (safer than KEYS for production)
// Uses SCAN iteratively instead of KEYS to avoid blocking Redis
app.get('/api/keys/search', async (req, res) => {
  try {
    const { pattern } = req.query;

    if (!pattern) {
      return res.status(400).json({
        error: 'Pattern parameter is required',
      });
    }

    if (!isValidSearchPattern(pattern)) {
      return res.status(400).json({
        error: 'Invalid search pattern. Only alphanumeric characters, *, ?, [, ], -, _, :, . are allowed.',
      });
    }

    // Use SCAN instead of KEYS to avoid blocking Redis on large databases
    const maxResults = 1000; // Limit results to prevent excessive memory usage
    const results = [];
    let cursor = 0;

    do {
      const reply = await redisClient.scan(cursor, {
        MATCH: pattern,
        COUNT: 100,
      });

      cursor = reply.cursor;
      results.push(...reply.keys);

      if (results.length >= maxResults) {
        break;
      }
    } while (cursor !== 0);

    const limitedResults = results.slice(0, maxResults);

    return res.json({
      pattern,
      count: limitedResults.length,
      truncated: results.length > maxResults,
      keys: limitedResults,
    });
  } catch (err) {
    console.error('Search error:', err.message);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// Execute allowed Redis commands
app.post('/api/command', async (req, res) => {
  try {
    const { command, args } = req.body;

    if (!command || typeof command !== 'string') {
      return res.status(400).json({
        error: 'Command is required and must be a string',
      });
    }

    const normalizedCommand = command.toUpperCase().trim();

    // Check against blocked commands first
    if (BLOCKED_COMMANDS.has(normalizedCommand)) {
      return res.status(403).json({
        error: 'This command is not permitted',
      });
    }

    // Check against allowlist
    const commandSpec = ALLOWED_COMMANDS[normalizedCommand];
    if (!commandSpec) {
      return res.status(403).json({
        error: 'This command is not in the allowed commands list',
        allowedCommands: Object.keys(ALLOWED_COMMANDS),
      });
    }

    // Validate args is an array
    const commandArgs = Array.isArray(args) ? args : [];

    // Ensure all args are strings or numbers (no objects, arrays, etc.)
    for (const arg of commandArgs) {
      if (typeof arg !== 'string' && typeof arg !== 'number') {
        return res.status(400).json({
          error: 'All arguments must be strings or numbers',
        });
      }
    }

    // Convert all args to strings for consistent handling
    const stringArgs = commandArgs.map(String);

    // Validate argument count
    if (stringArgs.length < commandSpec.minArgs || stringArgs.length > commandSpec.maxArgs) {
      return res.status(400).json({
        error: `Command ${normalizedCommand} requires between ${commandSpec.minArgs} and ${commandSpec.maxArgs} arguments, got ${stringArgs.length}`,
      });
    }

    // Validate individual arguments based on command type
    const validationErrors = validateCommandArgs(normalizedCommand, stringArgs);
    if (validationErrors.length > 0) {
      return res.status(400).json({
        error: 'Invalid arguments',
        details: validationErrors,
      });
    }

    // Execute the command using the Redis client's typed methods
    // This avoids using sendCommand with raw strings which could be manipulated
    let result;

    switch (normalizedCommand) {
      case 'GET':
        result = await redisClient.get(stringArgs[0]);
        break;
      case 'SET':
        result = await redisClient.set(stringArgs[0], stringArgs[1]);
        break;
      case 'DEL':
        result = await redisClient.del(stringArgs[0]);
        break;
      case 'EXISTS':
        result = await redisClient.exists(stringArgs[0]);
        break;
      case 'TTL':
        result = await redisClient.ttl(stringArgs[0]);
        break;
      case 'EXPIRE':
        result = await redisClient.expire(stringArgs[0], parseInt(stringArgs[1], 10));
        break;
      case 'TYPE':
        result = await redisClient.type(stringArgs[0]);
        break;
      case 'DBSIZE':
        result = await redisClient.dbSize();
        break;
      case 'PING':
        result = await redisClient.ping();
        break;
      case 'INFO':
        if (stringArgs.length === 1) {
          result = await redisClient.info(stringArgs[0]);
        } else {
          result = await redisClient.info();
        }
        break;
      case 'MGET':
        result = await redisClient.mGet(stringArgs);
        break;
      case 'STRLEN':
        result = await redisClient.strLen(stringArgs[0]);
        break;
      case 'APPEND':
        result = await redisClient.append(stringArgs[0], stringArgs[1]);
        break;
      case 'INCR':
        result = await redisClient.incr(stringArgs[0]);
        break;
      case 'DECR':
        result = await redisClient.decr(stringArgs[0]);
        break;
      case 'RENAME':
        result = await redisClient.rename(stringArgs[0], stringArgs[1]);
        break;
      default:
        return res.status(403).json({ error: 'Command not implemented' });
    }

    return res.json({
      command: normalizedCommand,
      args: stringArgs,
      result,
    });
  } catch (err) {
    // Don't leak internal Redis error details to the client
    console.error('Command execution error:', err.message);

    if (err.message && err.message.includes('WRONGTYPE')) {
      return res.status(400).json({
        error: 'Wrong type operation against a key holding a different type of value',
      });
    }

    if (err.message && err.message.includes('no such key')) {
      return res.status(404).json({
        error: 'Key not found',
      });
    }

    return res.status(500).json({ error: 'Internal server error' });
  }
});

